23	// ProviderStatuses is the resolver for the providerStatuses field.
24	// It mirrors the output of `ddx agent providers`, annotating each row with
25	// kind=ENDPOINT, a lastCheckedAt timestamp, and rolling usage derived from
26	// the sessions index. Quota is populated when the upstream ProviderInfo
27	// exposes token-level quota headers; null otherwise (FEAT-014 no-fabrication).
28	func (r *queryResolver) ProviderStatuses(ctx context.Context) ([]*ProviderStatus, error) {
29		now := time.Now().UTC()
30		entries := r.sessionIndexEntries()
31	
32		if rows := cachedProviderRows(r.WorkingDir); len(rows) > 0 {
33			refreshProviderStatuses(r.WorkingDir)
34			return providerRowsWithUsage(rows, entries, now), nil
35		}
36	
37		if snapshots, ok, err := agent.ConfiguredProviderSnapshots(r.WorkingDir); err == nil && ok {
38			rows := providerStatusesFromInfos(snapshots, entries, now)
39			storeProviderRows(r.WorkingDir, rows)
40			refreshProviderStatuses(r.WorkingDir)
41			return rows, nil
42		} else if err != nil {
43			return nil, fmt.Errorf("loading provider snapshots: %w", err)
44		}
45	
46		// Legacy/global provider config fallback. Bound the synchronous path so the
47		// UI can still first-paint harness rows even if provider probing is slow.
48		probeCtx, cancel := context.WithTimeout(ctx, 500*time.Millisecond)
49		defer cancel()
50		providers, err := liveProviderInfos(probeCtx, r.WorkingDir)
51		if err != nil {
52			refreshProviderStatuses(r.WorkingDir)
53			return []*ProviderStatus{}, nil
54		}
55		rows := providerStatusesFromInfos(providers, entries, now)
56		storeProviderRows(r.WorkingDir, rows)
57		return rows, nil
58	}
