60	// HarnessStatuses is the resolver for the harnessStatuses field.
61	// It returns one row per subprocess harness (kind=HARNESS). Reachability is
62	// taken from HarnessInfo.Available, rolling usage from the sessions index,
63	// and quota from the harness-reported rate-limit data when available.
64	func (r *queryResolver) HarnessStatuses(ctx context.Context) ([]*ProviderStatus, error) {
65		svc, err := agentlib.New(agentlib.ServiceOptions{})
66		if err != nil {
67			return []*ProviderStatus{}, nil //nolint:nilerr
68		}
69		infos, err := svc.ListHarnesses(ctx)
70		if err != nil {
71			return nil, fmt.Errorf("listing harnesses: %w", err)
72		}
73	
74		now := time.Now().UTC()
75		entries := r.sessionIndexEntries()
76		lastChecked := now.Format(time.RFC3339)
77	
78		results := make([]*ProviderStatus, 0, len(infos))
79		for _, info := range infos {
80			ps := &ProviderStatus{
81				Name:              info.Name,
82				Kind:              ProviderKindHarness,
83				ProviderType:      harnessTypeLabel(info),
84				BaseURL:           "(subprocess)",
85				Model:             info.DefaultModel,
86				Status:            harnessStatusLine(info),
87				Reachable:         info.Available,
88				Detail:            harnessDetail(info),
89				ModelCount:        harnessModelCount(info),
90				IsDefault:         false,
91				LastCheckedAt:     strPtr(lastChecked),
92				DefaultForProfile: []string{},
93			}
94			ps.Usage = buildUsage(entries, info.Name, agent.MatchHarness, now)
95			ps.Quota = quotaFromHarnessInfo(info)
96			results = append(results, ps)
97		}
98	
99		return results, nil
100	}
