102	// DefaultRouteStatus is the resolver for the defaultRouteStatus field.
103	func (r *queryResolver) DefaultRouteStatus(ctx context.Context) (*DefaultRouteStatus, error) {
104		svc, err := agent.NewServiceFromWorkDir(r.WorkingDir)
105		if err != nil {
106			return nil, nil //nolint:nilerr
107		}
108		dec, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{})
109		if err != nil {
110			return &DefaultRouteStatus{}, nil //nolint:nilerr
111		}
112		result := &DefaultRouteStatus{ModelRef: dec.Model}
113		if dec.Provider != "" {
114			p := dec.Provider
115			result.ResolvedProvider = &p
116		}
117		if dec.Model != "" {
118			m := dec.Model
119			result.ResolvedModel = &m
120		}
121		return result, nil
122	}
