124	// ProviderTrend is the resolver for the providerTrend field.
125	// It aggregates the sessions index into time buckets for one provider/harness
126	// and computes a projected-run-out-in-hours callout from the last-24h slope.
127	func (r *queryResolver) ProviderTrend(ctx context.Context, name string, windowDays int) (*ProviderTrend, error) {
128		name = strings.TrimSpace(name)
129		if name == "" {
130			return nil, fmt.Errorf("name required")
131		}
132		if windowDays != 7 && windowDays != 30 {
133			return nil, fmt.Errorf("windowDays must be 7 or 30")
134		}
135		now := time.Now().UTC()
136		entries := r.sessionIndexEntries()
137	
138		kind, detected := detectProviderOrHarness(ctx, r, name)
139		bucketKind := agent.MatchProvider
140		if kind == ProviderKindHarness {
141			bucketKind = agent.MatchHarness
142		}
143	
144		bucketSize := time.Hour
145		if windowDays > 7 {
146			bucketSize = 4 * time.Hour
147		}
148		buckets := agent.BucketUsage(entries, name, bucketKind, now, windowDays, bucketSize)
149		series := make([]*ProviderTrendPoint, 0, len(buckets))
150		for _, b := range buckets {
151			series = append(series, &ProviderTrendPoint{
152				BucketStart: b.Start.UTC().Format(time.RFC3339),
153				Tokens:      b.Tokens,
154				Requests:    b.Requests,
155			})
156		}
157	
158		trend := &ProviderTrend{
159			Name:       name,
160			Kind:       kind,
161			WindowDays: windowDays,
162			Series:     series,
163		}
164	
165		if detected != nil {
166			if ceiling := detected.ceilingTokens; ceiling > 0 {
167				c := ceiling
168				trend.CeilingTokens = &c
169				remaining := detected.remaining
170				if remaining < 0 {
171					remaining = ceiling - sumTailTokens(buckets, 24)
172				}
173				if p := projectRunOutHours(buckets, float64(remaining)); p > 0 {
174					trend.ProjectedRunOutHours = &p
175				}
176			}
177		}
178	
179		return trend, nil
180	}
