189	// detectProviderOrHarness looks up a name against providers first, then
190	// harnesses, returning the resolved kind and quota signal (if any).
191	func detectProviderOrHarness(ctx context.Context, r *queryResolver, name string) (ProviderKind, *detectedRow) {
192		if svc, err := agentlib.New(agentlib.ServiceOptions{}); err == nil {
193			harnesses, _ := svc.ListHarnesses(ctx)
194			for _, h := range harnesses {
195				if strings.EqualFold(h.Name, name) {
196					q := quotaFromHarnessInfo(h)
197					return ProviderKindHarness, detectedFromQuota(q)
198				}
199			}
200		}
201		if snapshots, ok, _ := agent.ConfiguredProviderSnapshots(r.WorkingDir); ok {
202			for _, p := range snapshots {
203				if strings.EqualFold(p.Name, name) {
204					q := quotaFromProviderInfo(p)
205					return ProviderKindEndpoint, detectedFromQuota(q)
206				}
207			}
208		}
209		if providers, err := liveProviderInfos(ctx, r.WorkingDir); err == nil {
210			for _, p := range providers {
211				if strings.EqualFold(p.Name, name) {
212					q := quotaFromProviderInfo(p)
213					return ProviderKindEndpoint, detectedFromQuota(q)
214				}
215			}
216		}
217		return ProviderKindEndpoint, nil
218	}
219	
220	func detectedFromQuota(q *ProviderQuota) *detectedRow {
221		if q == nil {
222			return nil
223		}
224		row := &detectedRow{ceilingTokens: -1, remaining: -1}
225		if q.CeilingTokens != nil {
226			row.ceilingTokens = *q.CeilingTokens
227		}
228		if q.Remaining != nil {
229			row.remaining = *q.Remaining
230		}
231		return row
232	}
