234	// projectRunOutHours returns the hours projected until current headroom is used
235	// based on the last-24-hour slope of the bucket series. Returns 0 when the
236	// slope is non-positive, headroom is gone/unknown, or the series is too
237	// short to estimate.
238	func projectRunOutHours(buckets []agent.UsageBucket, remaining float64) float64 {
239		if len(buckets) < 2 {
240			return 0
241		}
242		// Last 24 hours of buckets; if series is bucketed in 4h blocks, that's 6
243		// buckets; 1h buckets gives 24.
244		n := 24
245		if n > len(buckets) {
246			n = len(buckets)
247		}
248		tail := buckets[len(buckets)-n:]
249		tokens := make([]float64, len(tail))
250		for i, b := range tail {
251			tokens[i] = float64(b.Tokens)
252		}
253		perBucket := agent.LinearSlope(tokens)
254		// Convert slope-per-bucket to slope-per-hour.
255		var bucketHours float64
256		if len(tail) >= 2 {
257			bucketHours = tail[1].Start.Sub(tail[0].Start).Hours()
258		}
259		if bucketHours <= 0 {
260			bucketHours = 1
261		}
262		perHour := perBucket / bucketHours
263		if perHour <= 0 {
264			return 0
265		}
266		if remaining <= 0 {
267			return 0
268		}
269		hours := remaining / perHour
270		if hours <= 0 {
271			return 0
272		}
273		return hours
274	}
275	
276	func sumTailTokens(buckets []agent.UsageBucket, maxBuckets int) int {
277		if maxBuckets <= 0 || len(buckets) == 0 {
278			return 0
279		}
280		if maxBuckets > len(buckets) {
281			maxBuckets = len(buckets)
282		}
283		total := 0
284		for _, b := range buckets[len(buckets)-maxBuckets:] {
285			total += b.Tokens
286		}
287		return total
288	}
