290	func liveProviderInfos(ctx context.Context, workDir string) ([]agentlib.ProviderInfo, error) {
291		svc, err := agent.NewStatusProbeServiceFromWorkDir(workDir)
292		if err != nil {
293			return nil, err
294		}
295		return svc.ListProviders(ctx)
296	}
