298	func refreshProviderStatuses(workDir string) {
299		providerStatusCache.Lock()
300		if providerStatusCache.inFlight[workDir] {
301			providerStatusCache.Unlock()
302			return
303		}
304		providerStatusCache.inFlight[workDir] = true
305		providerStatusCache.Unlock()
306	
307		go func() {
308			defer func() {
309				providerStatusCache.Lock()
310				delete(providerStatusCache.inFlight, workDir)
311				providerStatusCache.Unlock()
312			}()
313			ctx, cancel := context.WithTimeout(context.Background(), 8*time.Second)
314			defer cancel()
315			providers, err := liveProviderInfos(ctx, workDir)
316			if err != nil {
317				return
318			}
319			rows := providerStatusesFromInfos(providers, nil, time.Now().UTC())
320			storeProviderRows(workDir, rows)
321		}()
322	}
323	
324	func cachedProviderRows(workDir string) []*ProviderStatus {
325		providerStatusCache.Lock()
326		defer providerStatusCache.Unlock()
327		return cloneProviderRows(providerStatusCache.rows[workDir])
328	}
329	
330	func storeProviderRows(workDir string, rows []*ProviderStatus) {
331		providerStatusCache.Lock()
332		defer providerStatusCache.Unlock()
333		providerStatusCache.rows[workDir] = cloneProviderRows(rows)
334	}
