336	func providerStatusesFromInfos(providers []agentlib.ProviderInfo, entries []agent.SessionIndexEntry, now time.Time) []*ProviderStatus {
337		lastChecked := now.UTC().Format(time.RFC3339)
338		results := make([]*ProviderStatus, 0, len(providers))
339		for _, p := range providers {
340			url := p.BaseURL
341			if url == "" {
342				url = "(api)"
343			}
344			ps := &ProviderStatus{
345				Name:              p.Name,
346				Kind:              ProviderKindEndpoint,
347				ProviderType:      p.Type,
348				BaseURL:           url,
349				Model:             p.DefaultModel,
350				Status:            p.Status,
351				Reachable:         providerReachable(p),
352				Detail:            providerDetail(p),
353				ModelCount:        p.ModelCount,
354				IsDefault:         p.IsDefault,
355				LastCheckedAt:     strPtr(lastChecked),
356				DefaultForProfile: defaultProfilesForEndpoint(p),
357			}
358			if ps.ProviderType == "" {
359				ps.ProviderType = "endpoint"
360			}
361			if p.CooldownState != nil && !p.CooldownState.Until.IsZero() {
362				s := p.CooldownState.Until.UTC().Format(time.RFC3339)
363				ps.CooldownUntil = &s
364			}
365			ps.Usage = buildUsage(entries, p.Name, agent.MatchProvider, now)
366			ps.Quota = quotaFromProviderInfo(p)
367			results = append(results, ps)
368		}
369		return results
370	}
