372	func providerRowsWithUsage(rows []*ProviderStatus, entries []agent.SessionIndexEntry, now time.Time) []*ProviderStatus {
373		out := cloneProviderRows(rows)
374		for _, row := range out {
375			row.Usage = buildUsage(entries, row.Name, agent.MatchProvider, now)
376		}
377		return out
378	}
379	
380	func cloneProviderRows(rows []*ProviderStatus) []*ProviderStatus {
381		if len(rows) == 0 {
382			return nil
383		}
384		out := make([]*ProviderStatus, 0, len(rows))
385		for _, row := range rows {
386			if row == nil {
387				continue
388			}
389			clone := *row
390			if row.DefaultForProfile != nil {
391				clone.DefaultForProfile = append([]string(nil), row.DefaultForProfile...)
392			}
393			out = append(out, &clone)
394		}
395		return out
396	}
