398	// sessionIndexEntries reads the project's session index for all available
399	// shards. Errors are swallowed — a missing index is a normal "no data" state.
400	func (r *queryResolver) sessionIndexEntries() []agent.SessionIndexEntry {
401		logDir := agent.SessionLogDirForWorkDir(r.WorkingDir)
402		if logDir == "" {
403			return nil
404		}
405		entries, err := agent.ReadSessionIndex(logDir, agent.SessionIndexQuery{})
406		if err != nil {
407			return nil
408		}
409		return entries
410	}
