412	func buildUsage(entries []agent.SessionIndexEntry, name string, kind agent.UsageMatchKind, now time.Time) *ProviderUsage {
413		counts := agent.AggregateUsageCounts(entries, name, kind, now)
414		u := &ProviderUsage{}
415		v := counts.TokensLastHour
416		u.TokensUsedLastHour = &v
417		v2 := counts.TokensLast24h
418		u.TokensUsedLast24h = &v2
419		v3 := counts.RequestsLastHour
420		u.RequestsLastHour = &v3
421		v4 := counts.RequestsLast24h
422		u.RequestsLast24h = &v4
423		return u
424	}
