426	// quotaFromProviderInfo derives a ProviderQuota from the upstream ProviderInfo.
427	// Returns nil when no token-level ceiling is published.
428	func quotaFromProviderInfo(p agentlib.ProviderInfo) *ProviderQuota {
429		if p.Quota == nil {
430			return nil
431		}
432		return quotaFromState(p.Quota)
433	}
434	
435	// quotaFromHarnessInfo derives a ProviderQuota from the upstream HarnessInfo.
436	// Returns nil when no token-level ceiling is published.
437	func quotaFromHarnessInfo(info agentlib.HarnessInfo) *ProviderQuota {
438		if info.Quota == nil {
439			return nil
440		}
441		return quotaFromState(info.Quota)
442	}
443	
444	// quotaFromState derives a ProviderQuota from an upstream QuotaState. The
445	// upstream QuotaWindow doesn't expose absolute token ceilings (only percent
446	// used), so we surface the window length and reset time only. Ceiling and
447	// remaining stay unknown unless a harness-specific rate-limit-header path
448	// populates them via QuotaFromRateLimitSignal.
449	func quotaFromState(state *agentlib.QuotaState) *ProviderQuota {
450		if state == nil || len(state.Windows) == 0 {
451			return nil
452		}
453		var windowSeconds int
454		var resetAt string
455		for _, w := range state.Windows {
456			if strings.EqualFold(w.LimitID, "extra") {
457				continue
458			}
459			if windowSeconds == 0 && w.WindowMinutes > 0 {
460				windowSeconds = w.WindowMinutes * 60
461			}
462			if resetAt == "" {
463				if w.ResetsAt != "" {
464					resetAt = w.ResetsAt
465				} else if w.ResetsAtUnix > 0 {
466					resetAt = time.Unix(w.ResetsAtUnix, 0).UTC().Format(time.RFC3339)
467				}
468			}
469			if windowSeconds > 0 && resetAt != "" {
470				break
471			}
472		}
473		if windowSeconds == 0 && resetAt == "" {
474			return nil
475		}
476		q := &ProviderQuota{}
477		if windowSeconds > 0 {
478			v := windowSeconds
479			q.CeilingWindowSeconds = &v
480		}
481		if resetAt != "" {
482			v := resetAt
483			q.ResetAt = &v
484		}
485		return q
486	}
487	
488	// QuotaFromRateLimitSignal produces a ProviderQuota from a parsed rate-limit
489	// header signal (see agent.ParseRateLimitHeaders). Exposed for future call
490	// sites where the server captures harness response headers.
491	func QuotaFromRateLimitSignal(sig agent.RateLimitSignal) *ProviderQuota {
492		if !sig.HasAny() {
493			return nil
494		}
495		q := &ProviderQuota{}
496		if sig.CeilingTokens >= 0 {
497			v := sig.CeilingTokens
498			q.CeilingTokens = &v
499		}
500		if sig.CeilingWindowSeconds >= 0 {
501			v := sig.CeilingWindowSeconds
502			q.CeilingWindowSeconds = &v
503		}
504		if sig.Remaining >= 0 {
505			v := sig.Remaining
506			q.Remaining = &v
507		}
508		if !sig.ResetAt.IsZero() {
509			v := sig.ResetAt.UTC().Format(time.RFC3339)
510			q.ResetAt = &v
511		}
512		return q
513	}
514	
515	// defaultProfilesForEndpoint returns the profile names where this endpoint is
516	// a default candidate. Current service surface exposes only a single
517	// IsDefault flag, so we return ["default"] when set, [] otherwise. The return
518	// shape supports multi-profile expansion without breaking callers.
519	func defaultProfilesForEndpoint(p agentlib.ProviderInfo) []string {
520		if p.IsDefault {
521			return []string{"default"}
522		}
523		return []string{}
524	}
525	
526	func providerReachable(p agentlib.ProviderInfo) bool {
527		return strings.EqualFold(strings.TrimSpace(p.Status), "connected")
528	}
529	
530	func providerDetail(p agentlib.ProviderInfo) string {
531		if p.LastError != nil && strings.TrimSpace(p.LastError.Detail) != "" {
532			return p.LastError.Detail
533		}
534		for _, ep := range p.EndpointStatus {
535			if ep.LastError != nil && strings.TrimSpace(ep.LastError.Detail) != "" {
536				return ep.LastError.Detail
537			}
538			if strings.TrimSpace(ep.Status) != "" && !strings.EqualFold(ep.Status, p.Status) {
539				return ep.Status
540			}
541		}
542		if strings.TrimSpace(p.Status) != "" {
543			if strings.EqualFold(p.Status, "unknown") {
544				return "not checked yet"
545			}
546			return p.Status
547		}
548		return "not reported"
549	}
550	
551	func harnessTypeLabel(info agentlib.HarnessInfo) string {
552		if info.Type != "" {
553			return info.Type
554		}
555		return "subprocess"
556	}
557	
558	func harnessStatusLine(info agentlib.HarnessInfo) string {
559		if info.Available {
560			return "available"
561		}
562		if info.Error != "" {
563			return "unavailable: " + info.Error
564		}
565		return "unavailable"
566	}
567	
568	func harnessDetail(info agentlib.HarnessInfo) string {
569		if info.LastError != nil && strings.TrimSpace(info.LastError.Detail) != "" {
570			return info.LastError.Detail
571		}
572		if strings.TrimSpace(info.Error) != "" {
573			return info.Error
574		}
575		if info.Available && strings.TrimSpace(info.Path) != "" {
576			return info.Path
577		}
578		if info.Available {
579			return "available"
580		}
581		return "binary not found"
582	}
583	
584	func harnessModelCount(_ agentlib.HarnessInfo) int {
585		// Harness-reported model counts flow through a separate model-discovery
586		// path; leave 0 until that surface is exposed to avoid fabricating a
587		// number from capability flags.
588		return 0
589	}
