9	// RateLimitSignal is a normalized rate-limit snapshot parsed from harness
10	// HTTP response headers. All fields are optional; an unset integer field is
11	// represented by -1 so callers can distinguish "unknown" from "zero".
12	type RateLimitSignal struct {
13		CeilingTokens        int       // -1 when unknown
14		CeilingWindowSeconds int       // -1 when unknown
15		Remaining            int       // -1 when unknown
16		ResetAt              time.Time // zero when unknown
17	}
18	
19	// HasAny reports whether any field is populated.
20	func (s RateLimitSignal) HasAny() bool {
21		if s.CeilingTokens >= 0 {
22			return true
23		}
24		if s.CeilingWindowSeconds >= 0 {
25			return true
26		}
27		if s.Remaining >= 0 {
28			return true
29		}
30		if !s.ResetAt.IsZero() {
31			return true
32		}
33		return false
34	}
35	
36	// ParseRateLimitHeaders parses the common rate-limit headers emitted by
37	// subprocess harnesses that wrap provider HTTP calls. The harness name selects
38	// the header family. Headers not recognised by the mapping are ignored.
39	//
40	// Supported families:
41	//   - "claude": anthropic-ratelimit-tokens-{limit,remaining,reset} and
42	//     anthropic-ratelimit-requests-{limit,remaining,reset}. The tokens family
43	//     wins when both are present.
44	//   - "codex":  x-ratelimit-{limit,remaining,reset}-tokens (OpenAI/codex).
45	//
46	// Unknown harnesses return an empty signal.
47	func ParseRateLimitHeaders(harness string, headers map[string][]string) RateLimitSignal {
48		h := normalizeHeaders(headers)
49		sig := emptyRateLimitSignal()
50		switch strings.ToLower(strings.TrimSpace(harness)) {
51		case "claude", "anthropic":
52			sig = parseClaudeRateLimit(h)
53		case "codex", "openai":
54			sig = parseCodexRateLimit(h)
55		}
56		return sig
57	}
58	
59	func emptyRateLimitSignal() RateLimitSignal {
60		return RateLimitSignal{
61			CeilingTokens:        -1,
62			CeilingWindowSeconds: -1,
63			Remaining:            -1,
64		}
65	}
66	
67	// normalizeHeaders lowercases and flattens map[string][]string → map[string]string.
68	// The first value for each header wins.
69	func normalizeHeaders(headers map[string][]string) map[string]string {
70		out := make(map[string]string, len(headers))
71		for k, v := range headers {
72			if len(v) == 0 {
73				continue
74			}
75			out[strings.ToLower(strings.TrimSpace(k))] = strings.TrimSpace(v[0])
76		}
77		return out
78	}
79	
80	// parseClaudeRateLimit reads the anthropic-ratelimit-* header family.
81	// Anthropic publishes separate windows for tokens and requests; tokens is the
82	// more useful signal for "will we run out soon", so we prefer it.
83	func parseClaudeRateLimit(h map[string]string) RateLimitSignal {
84		sig := emptyRateLimitSignal()
85		if limit, ok := parseIntHeader(h, "anthropic-ratelimit-tokens-limit"); ok {
86			sig.CeilingTokens = limit
87		}
88		if rem, ok := parseIntHeader(h, "anthropic-ratelimit-tokens-remaining"); ok {
89			sig.Remaining = rem
90		}
91		if resetStr, ok := h["anthropic-ratelimit-tokens-reset"]; ok {
92			if t, ok2 := parseResetTimestamp(resetStr); ok2 {
