96		// If tokens family not populated, fall back to requests family for resetAt/window.
97		if sig.CeilingTokens < 0 && sig.Remaining < 0 {
98			if limit, ok := parseIntHeader(h, "anthropic-ratelimit-requests-limit"); ok {
99				sig.CeilingTokens = limit
100			}
101			if rem, ok := parseIntHeader(h, "anthropic-ratelimit-requests-remaining"); ok {
102				sig.Remaining = rem
103			}
104			if resetStr, ok := h["anthropic-ratelimit-requests-reset"]; ok {
105				if t, ok2 := parseResetTimestamp(resetStr); ok2 {
106					sig.ResetAt = t
107				}
108			}
109		}
110		if sig.HasAny() {
111			// Anthropic rate-limit windows are published as 1-minute buckets for
112			// token-level quotas. Record the window so clients can render "/ min".
113			sig.CeilingWindowSeconds = 60
114		}
115		return sig
116	}
117	
118	// parseCodexRateLimit reads the x-ratelimit-*-tokens header family.
119	func parseCodexRateLimit(h map[string]string) RateLimitSignal {
120		sig := emptyRateLimitSignal()
121		if limit, ok := parseIntHeader(h, "x-ratelimit-limit-tokens"); ok {
122			sig.CeilingTokens = limit
123		}
124		if rem, ok := parseIntHeader(h, "x-ratelimit-remaining-tokens"); ok {
125			sig.Remaining = rem
126		}
127		if resetStr, ok := h["x-ratelimit-reset-tokens"]; ok {
128			if t, ok2 := parseResetTimestamp(resetStr); ok2 {
129				sig.ResetAt = t
130			}
131		}
132		if sig.HasAny() {
133			sig.CeilingWindowSeconds = 60
134		}
135		return sig
136	}
137	
138	func parseIntHeader(h map[string]string, key string) (int, bool) {
139		v, ok := h[key]
140		if !ok || v == "" {
141			return 0, false
142		}
143		n, err := strconv.Atoi(v)
144		if err != nil {
145			return 0, false
146		}
147		return n, true
148	}
149	
150	// parseResetTimestamp accepts either an absolute RFC3339 timestamp (Anthropic
151	// style) or a relative "30s" / "2m" / "1h" duration (codex style).
152	func parseResetTimestamp(s string) (time.Time, bool) {
153		s = strings.TrimSpace(s)
154		if s == "" {
155			return time.Time{}, false
156		}
157		if t, err := time.Parse(time.RFC3339, s); err == nil {
158			return t.UTC(), true
159		}
160		if d, err := time.ParseDuration(s); err == nil {
161			return time.Now().UTC().Add(d), true
162		}
163		if secs, err := strconv.Atoi(s); err == nil {
164			return time.Unix(int64(secs), 0).UTC(), true
165		}
166		return time.Time{}, false
167	}
